mapper.select:
 SELECT
		DATE_FORMAT(REG_DATE, '%Y-%m') AS USER_MONTH, Count(*) AS USER_COUNT
		FROM MEMBER WHERE 1=1 
			AND ROLE = #{role}
		 GROUP BY USER_MONTH ORDER BY
		USER_MONTH;

SELECT price
FROM PASS_PRODUCT
WHERE PASS_NO = #{passNo}

mapper.insert:
INSERT INTO payment_pass (
pay_no,
pass_no,
item_name
)
VALUES (
#{payNo},
#{passNo},
#{itemName}
)

mapper.select:
SELECT COUNT(*)
FROM inquiry_answer
WHERE inquiry_no = #{inquiryNo}

mapper.insert:
INSERT INTO inquiry_answer (
inquiry_no,
content
) VALUES (
#{inquiryNo},
#{answer}
)

mapper.update:
UPDATE inquiry_answer
SET content = #{answer}
WHERE inquiry_no = #{inquiryNo}

UPDATE inquiry
SET status = 'DONE'
WHERE inquiry_no = #{inquiryNo}

mapper.select:
SELECT p.post_no AS postNo, p.user_id AS userId, p.category, p.title, p.content, p.reg_date AS regDate, p.view_cnt AS viewCnt, p.like_cnt AS likeCnt, p.is_deleted AS isDeleted,
( SELECT COUNT(*) FROM comment c WHERE c.post_no = p.post_no AND c.is_deleted = 0 ) AS commentCnt
FROM Community_Post p WHERE p.post_no = #{postNo}

mapper.update:
UPDATE member
SET status = #{status}
WHERE user_id = #{target_id}

UPDATE report
SET action_status = 1
WHERE report_no = #{reportNo}

UPDATE report
SET action_status = 2,
	reject_reason = #{rejectReason}
WHERE report_no = #{reportNo}

mapper.select:
SELECT * FROM payment
ORDER BY pay_no DESC
LIMIT #{pageSize} OFFSET #{offSet}
